def summera(lista):
  summa = 0
  for tal in lista:
    summa+= tal
  return summa

def multiplicera(lista):
  produkt = 1
  for tal in lista:
    produkt *= tal
  return produkt

def beräkna_medelvärde(lista):
  summa = summera(lista)
  medelvärde = summa/len(lista)
  return medelvärde
